const lamps = [];
for (let i = 1; i <= 14; i++) {
  lamps.push(`MainHouse-Kitchen_${i}`);
}
global.set('rainbowActive', true);
const goldenAngle = 137.508;
const cycles = {};
lamps.forEach((lamp, index) => {
  cycles[lamp] = (index * goldenAngle) % 360;
});
global.set('lampCycles', cycles);
global.set('lamps', lamps);
node.status({fill: "green", shape: "dot", text: "Laeuft - 14 Lampen"});
return {payload: `Rainbow gestartet - ${lamps.length} Lampen`};

if (!global.get('rainbowActive')) {
  return null;
}
const lamps = global.get('lamps');
const lampCycles = global.get('lampCycles');
if (!lamps || !lampCycles) {
  node.warn('Lamps oder lampCycles nicht initialisiert');
  return null;
}
Object.keys(lampCycles).forEach(lamp => {
  lampCycles[lamp] = (lampCycles[lamp] + 20) % 360;
});
global.set('lampCycles', lampCycles);
const messages = [];
lamps.forEach((lamp) => {
  const hue = lampCycles[lamp];
  messages.push({
    topic: `zigbee2mqtt/${lamp}/set`,
    payload: JSON.stringify({
      color: { h: hue, s: 100 },
      brightness: 200,
      transition: 0.4
    })
  });
});
return [messages];

global.set('rainbowActive', false);
node.status({fill: "red", shape: "dot", text: "Gestoppt"});
return {payload: "Rainbow gestoppt"};

